INSERT OR IGNORE INTO posts (id, bbsid, board_id, user_id, title, content, content_text, signature, posted_at, reply_count, source_file, wayback_ts) VALUES (1458, 194929, 6, 1942, '梅子老爹', '梅子老爹不卖梅子，他只卖梅子绿茶。
<br>梅子老爹也不老，只因他姓邓，而小镇的方言中邓与爹谐音，老邓也就缘此讹成了老爹。
<br>梅子老爹的茶馆就在我们中学校门的正对面，一座青黄色的竹木小屋，平凡中透着几分雅致。茶馆的名字极富特色，“聆心小筑”，不带半丝人间烟火气息，字眼之中竟泛出几分“采菊东篱下，悠然见南山”的古韵。
<br>茶馆的生意不算兴隆，光顾的大多数是我们这些两袖清风的穷学生。茶馆经营的品种十分单一，只卖梅子绿茶。两毛钱一杯，续杯免费。杯子用上年头的竹节制成，未加任何雕琢，泛着几分苍凉古拙的味道。茶馆的旁边有一条小溪，溪水清澈见底，是泡茶的上品。
<br>我们常选在夜幕降临、华灯初上之时蹩进聆心小筑。三两个知己，围坐于屋角一隅。梅子老爹总是适时的端上几盅盛好茶叶和新鲜梅子的竹杯来，一一冲上沸腾的热水放在我们的面前。杯中的茶叶受了水的滋润，慢慢地舒展开来，仿佛一个个绿色的小精灵，争先恐后的浮出水面，在腾腾水雾中诠释各自轻灵的舞姿，逐渐将原本清澈的水带出些许绿意，淡淡的清香也慢慢在空气中弥散开来。不过没多久，这些绿色的小精灵们就舞得乏了，于是恋恋不舍的退回到杯底，一泓碧水中，红色的梅子慢慢现出了身形，在绿色的映衬之下，那一抹抹红色显得分外娇艳，似乎快要滴出血来。我们终于抵受不住这“绿肥红瘦”的蛊惑，就着满屋浮动的暗香轻轻抿上一口，闭上眼睛细细品味。梅子的微酸恰倒好处的隐去了绿茶的些许青涩，因而茶水入口显得分外的绵香醇厚。几口茶下肚，一种淡淡的馨香仿佛从心底的最深处慢慢地沁出开去，借着股柔柔的暖意不安分地四处游走。心，却因此变得淡定。小镇的喧嚣在身后逐渐褪去，耳畔留住的只有小屋隐隐回荡的，如同天籁一般的《高山流水》。在小屋柔和的灯光下，我们拾起一天的疲惫，或开始一天的功课，或拿出一本心仪已久的好书静静品味，或在白纸上倾吐自己的心语，用文字涂抹着自己的花季和雨季……在这个属于我们自己的小小世界里，所有的语言都显得如此苍白和多余，只有在偶尔抬首四目相交的瞬间，传递着彼此的温馨和喜悦。
<br>一来二去，我们便和梅子老爹混得厮熟。老爹人极随和，有着不俗的谈吐和广博的见闻，尤其在文学方面有极深的造诣，朴素但整洁的衣着透着股浓浓的书卷气。亦师亦友这四个字用来形容我们同老爹的关系真是再恰当不过了。老爹还写得一手遒劲的魏碑，行草也颇见功底，逢年过节或镇上人家的红白喜事总少不了老爹的墨宝，老爹也从不推脱，总能让大家满意而归。我们看得稀奇，缠着老爹要教我们几手，但少年人终究心性不定，未过数日便纷纷偃旗息鼓，作鸟兽散。老爹是个随性之人，并不勉强我们，最多的表示也只是摇摇头，眼光中颇有几分恨铁不成钢的意思。
<br>老爹有个极可爱的女儿，大约三、四岁光景，梳着羊角小辨，长长的睫毛下藏着一双水灵灵的大眼睛，白里透红的皮肤我见犹怜，眉宇之间竟可以看出几分老爹的影子，活脱脱一个江南水乡的小美人胚子。我们极喜欢逗她玩儿，兴致来时，也会班门弄斧的在老爹面前教她背一些古诗和童谣，小女孩极赋灵性，往往用不了两三遍就背得滚瓜烂熟；而作为交换，她会偷偷在我们续杯的茶水中额外的加上一颗梅子。老爹看在眼里，并不做声，只是笑笑。
<br>关于茶馆里缺少的那个女主人的下落，我们曾做过种种的推测，可是均因无法得到应证而作罢。每每问及，小女孩会用她稚气的童音耐心的告诉我们她的妈妈去了一个很远很远的地方，而老爹则多会用一些笑话支开话题，顾左右而言他，也怪我们当时还太小，都忽略了老爹笑容背后掠过的一丝无奈和伤感。
<br>突然有一天，茶馆门前来了一辆漂亮的小车，车上下来一个珠光宝气的美丽少妇，摇曳有姿地走进茶馆。没有多久，少妇就走了，并且带走了老爹心爱的女儿。那一天，小镇下着蒙蒙细雨，阴霾的天空中仿佛飘荡着一个小女孩凄厉的哭泣声，久久不散。
<br>女儿走后，老爹仿佛变了一个人，常常挂在脸上的微笑不见了，睿智的眼神也失去了往日的光芒。再去茶馆，老爹懒得招呼我们，只是让我们自己动手，而他却躲进屋角的阴影里拿出一张相片呆呆的看着，孤独无助的背影中似乎写满了伤心和无奈。
<br>在我的记忆中，那一年的冬天似乎来得特别的早。淋漓的冬雨连绵不绝，下了整整一个多月，终于在除夕前的一个晚上，镇里百年一遇的山洪暴发了，原本温顺的小溪肆虐着冲出了堤岸。聆心小筑就在那个风雨飘摇的夜里化为一堆废墟，屋子里的老爹再也没有走出来。 
<br>老爹走得极安详，一片废墟之中，他的面部奇迹般的完好无损，那上面没有一丝痛苦的表情和濒死时的恐惧。失去血色的苍白眸子直直的望着远方，似有无限期待，嘴角微微牵向一侧，不经意看去，竟似挂着一丝神秘的微笑。小镇的人们整理老爹的遗物时，在他的贴身衣服口袋中找到了那张相片。照片上老爹和一个抱着婴儿的女子站在一片梅林前，柔柔的阳光下，老爹笑得一脸灿烂。
<br>后来从大人的片言只语中，我们渐渐了解的老爹的身世。老爹出生在一个偏僻的小山村，家境贫寒，但老爹自小天资过人，以优异的成绩考上了江南一所名牌大学的中文系。在大学里，老爹遇见了一个出身江南，有着显赫家族背景的女孩。女孩羡慕老爹的才气，而老爹则惊艳于江南女子的美丽，于是爱得死去活来。大学毕业之后，两人不顾来自女方家庭的强烈反对，离家出走并在小镇上安下了家。结婚之后，他们曾有过一段幸福的时光，女孩爱吃新鲜的梅子，每当小镇后山的梅子红时，老爹便会捧回一大堆梅子，然后看着心爱的女孩一点点的吃光。然而这份幸福似乎太短暂了，随着女儿的降生，原本拮据的生活更加捉襟见肘起来，现实渐渐显露出了它那残酷的另一面，慢慢的，女孩再也无法忍受这种清贫的生活，在一个夜里悄悄的离开了他，只留下了一张签了名的离婚协议书。老爹不死心，仍带着女儿在镇上靠一间茶屋苦苦维持着生计，他一直相信女孩总有一天会回心转意，再次回到他的身边。几年后，女人终于回来了，却只是要回来带走他们的女儿，老爹万念俱灰，为了女儿不再和自己一起受苦，也为了女儿有一个更加光明的未来，老爹最终选择了放弃。那个女人也许不知道自己在带走老爹最心爱的东西的同时，也不经意地带走了老爹对生活的最后一丝美好憧憬和眷恋……
<br>老爹走后不久，家人调动工作，我便随父母离开了小镇。走的那天，小镇下着绵绵细雨，车子经过老爹小屋的旧址时，我透过湿湿的车窗向外望去，一片朦胧中，我仿佛又看到了散发着淡淡梅子绿茶香味的聆心小筑，以及小筑里那个写满无奈的惆怅背影，耳边隐约回荡着那个小女孩银铃般的笑声。刹那间，所有关于小屋的往事一一涌上心头，令我无法大口呼吸。父母关切的望着我，我想告诉他们我没事，可是却说不出话来，于是我努力对他们做出一个笑容，却不争气的让蓄积已久的泪水夺眶而出，在脸上肆意流淌……
<br>多年以后，由于工作方面的一些原因我又再一次回到了小镇。和旧时好友漫步夜色阑珊的小镇街头，仿佛在穿越长长的时空隧道，记忆中的小镇已变了模样，四处是林立的高楼，原来的母校已经迁到别处，取而代之的是一间挨着一间的酒吧和发廊，镇上的那条小溪早已不再清澈，自从镇上有了自来水后，已经很少人再用溪水了。好友带我走进一家生意兴隆的茶楼，热情的小姐端上一套精美的茶具，我点了一泡“明前”，并特意让小姐给我的茶里加一颗梅子，小姐虽然不解，但还是熟练地泡好了一杯送到我的面前。茶水依旧甘甜，而我却怅然若失，因为我突然意识到，记忆中那杯泛着淡淡香味的梅子绿茶就如逝去的少年时光一般一去不复返，今生今世，我们再也无缘相见，不复再见！', '梅子老爹不卖梅子，他只卖梅子绿茶。

